import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import MoveForward from "@components/common/move-forward";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import SmartContractScreen from "@screens/smart-contract";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const SmartContract = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Smart Contract Development Services", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.smartContractDevImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Explore Justtry Technologies, Secure smart contract development for blockchain apps. We build audited, scalable contracts for DeFi, NFTs & enterprises.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1567",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What does a smart contract developer do?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A smart contract developer designs, builds, tests, and deploys self-executing contracts on blockchain networks to automate agreements without intermediaries.",
            },
          },
          {
            "@type": "Question",
            name: "What is the smart contract development process?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The smart contract development process involves requirement analysis, contract design, coding, testing, security auditing, deployment, and ongoing maintenance on the blockchain.",
            },
          },
          {
            "@type": "Question",
            name: "What platform is smart contract development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Smart contract development is done on blockchain platforms such as Ethereum, Binance Smart Chain, Solana, Polygon, and Hyperledger.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        schemaMarkup={schemaMarkup}
        slug={location.pathname.split("/")?.[1]}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <SmartContractScreen db={db} />
      {/* <MoveForward db={db} /> */}
    </Layout_v2>
  );
};

export default SmartContract;

export const queryData = graphql`
  query MyQuery {
    smartContractDevImg: file(
      relativePath: { eq: "smart-contract-development.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "smart-contract-development-company" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
